import '../lib/release_manager.dart';
import '../lib/release_store.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final store = ReleaseStore()
    ..add('blue', {'asset.txt': 'blue asset'})
    ..add('green', {'asset.txt': 'green asset'});
  final manager = ReleaseManager(store)..activate('blue');
  final inFlight = manager.openActive();

  manager.activate('green');
  check(store.contains('blue'), 'a retired release remains while a reader uses it');
  check(inFlight.read('asset.txt') == 'blue asset',
      'the existing reader keeps a stable release snapshot');

  inFlight.close();
  check(!store.contains('blue'), 'the retired release is removed after its reader closes');
  check(store.contains('green'), 'closing an old reader does not remove the active release');
}
